// ============================================================
// Parse the chat message to extract a PyPI package name.
// Handles natural phrasing like:
//   "check transformers"
//   "is langchain safe?"
//   "vet openai"
//   "transformers"   (just the name)
// Defaults to 'langchain' if the message is empty or unclear.
// ============================================================
const raw = ($input.first().json.chatInput || '').trim();

const cleaned = raw
  .replace(/^(check|vet|scan|analyze|inspect|audit|is|evaluate|review)\s+/i, '')
  .replace(/\s+(safe|secure|ok|risky|vulnerable|compromised|trustworthy|legit|legitimate)\??$/i, '')
  .replace(/^(the\s+)?(package|library|module|dependency|pip\s+package|pypi\s+package)\s+/i, '')
  .replace(/^(pypi|pip)\s*[:\/]\s*/i, '')
  .replace(/["'`]/g, '')
  .trim()
  .split(/\s+/)[0] || '';  // take first word if multiple remain

const package_name = cleaned || 'langchain';

return [{
  json: {
    package_name,
    original_input: raw,
    session_id: $input.first().json.sessionId || 'default'
  }
}];

// ============================================================
// Extract and normalize supply-chain signals from PyPI + OSV
// ============================================================
const pypiRaw = $('Fetch PyPI Metadata').first().json;
const osvRaw  = $input.first().json;
const pkgName = $('Parse Package Name').first().json.package_name;

// --- Handle PyPI 404 / error ---
const pypiOk = !!(pypiRaw?.info?.name);
if (!pypiOk) {
  return [{
    json: {
      package_name: pkgName,
      pypi_found: false,
      osv_vulns: [],
      signals: {},
      flags: ['PACKAGE_NOT_FOUND: This package does not exist on PyPI. If you expected it to exist, this itself is a supply-chain signal — verify the spelling and source.'],
      flag_count: 1
    }
  }];
}

const info = pypiRaw.info;
const releases = pypiRaw.releases || {};
const releaseNames = Object.keys(releases);

// --- Compute age from earliest release ---
let firstReleaseDate = null;
let lastReleaseDate = null;
for (const ver of releaseNames) {
  const files = releases[ver] || [];
  for (const f of files) {
    const d = f.upload_time ? new Date(f.upload_time) : null;
    if (d) {
      if (!firstReleaseDate || d < firstReleaseDate) firstReleaseDate = d;
      if (!lastReleaseDate  || d > lastReleaseDate)  lastReleaseDate = d;
    }
  }
}

const now = new Date();
const ageDays = firstReleaseDate ? Math.floor((now - firstReleaseDate) / 86400000) : null;
const daysSinceLastRelease = lastReleaseDate ? Math.floor((now - lastReleaseDate) / 86400000) : null;

// --- Extract project URLs ---
const projectUrls = info.project_urls || {};
const hasSourceRepo = Object.values(projectUrls).some(u =>
  /github\.com|gitlab\.com|bitbucket\.org|codeberg\.org/i.test(u)
);
const homepage = info.home_page || projectUrls['Homepage'] || projectUrls['Home'] || null;

// --- OSV vulnerabilities ---
const vulns = (osvRaw?.vulns || []).map(v => ({
  id: v.id,
  summary: (v.summary || '').slice(0, 120),
  severity: v.database_specific?.severity || v.severity?.[0]?.score || 'unknown',
  published: v.published || null
}));

// --- Dependencies ---
const deps = (info.requires_dist || []).map(d => d.split(';')[0].split(/[<>=!\[]/)[0].trim());

// --- Known popular packages (for typosquat check) ---
const popular = [
  'requests','numpy','pandas','flask','django','transformers','torch','tensorflow',
  'langchain','openai','anthropic','scikit-learn','scipy','boto3','fastapi','celery',
  'pillow','matplotlib','pydantic','httpx','aiohttp','beautifulsoup4','selenium'
];

const levenshtein = (a, b) => {
  const m = a.length, n = b.length;
  const dp = Array.from({length: m+1}, (_,i) => {
    const row = new Array(n+1);
    row[0] = i;
    return row;
  });
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++)
    for (let j = 1; j <= n; j++)
      dp[i][j] = Math.min(
        dp[i-1][j] + 1,
        dp[i][j-1] + 1,
        dp[i-1][j-1] + (a[i-1] !== b[j-1] ? 1 : 0)
      );
  return dp[m][n];
};

const typosquatCandidates = popular
  .filter(p => p !== pkgName && levenshtein(p, pkgName) <= 2 && levenshtein(p, pkgName) > 0)
  .slice(0, 3);

// --- Build signals object ---
const signals = {
  name: info.name,
  version: info.version,
  author: info.author || info.maintainer || 'unknown',
  author_email: info.author_email || info.maintainer_email || 'unknown',
  license: info.license || 'NOT SPECIFIED',
  summary: (info.summary || '').slice(0, 200),
  homepage,
  has_source_repo: hasSourceRepo,
  project_urls: projectUrls,
  total_releases: releaseNames.length,
  first_release: firstReleaseDate ? firstReleaseDate.toISOString().slice(0, 10) : 'unknown',
  latest_release: lastReleaseDate ? lastReleaseDate.toISOString().slice(0, 10) : 'unknown',
  age_days: ageDays,
  days_since_last_release: daysSinceLastRelease,
  python_requires: info.requires_python || 'any',
  dependency_count: deps.length,
  dependencies: deps.slice(0, 20),
  known_vulnerabilities: vulns.length,
  vulnerability_details: vulns.slice(0, 10),
  typosquat_similar_to: typosquatCandidates
};

// --- Heuristic flags ---
const flags = [];

if (ageDays !== null && ageDays < 30)
  flags.push(`VERY_NEW: Package is only ${ageDays} days old. New packages have no track record.`);
if (ageDays !== null && ageDays < 180 && ageDays >= 30)
  flags.push(`YOUNG: Package is ${ageDays} days old (< 6 months). Exercise caution.`);
if (!hasSourceRepo)
  flags.push('NO_SOURCE_REPO: No GitHub/GitLab/Bitbucket link found. Cannot inspect source code.');
if (!info.license || info.license === 'UNKNOWN')
  flags.push('NO_LICENSE: No license specified. Unusual for legitimate packages.');
if (releaseNames.length <= 2)
  flags.push(`FEW_RELEASES: Only ${releaseNames.length} release(s). Low maturity signal.`);
if (vulns.length > 0)
  flags.push(`KNOWN_CVES: ${vulns.length} known vulnerability(ies) in OSV database.`);
if (typosquatCandidates.length > 0)
  flags.push(`TYPOSQUAT_RISK: Name is suspiciously close to: ${typosquatCandidates.join(', ')}.`);
if (daysSinceLastRelease !== null && daysSinceLastRelease > 730)
  flags.push(`STALE: Last release was ${daysSinceLastRelease} days ago (> 2 years). May be abandoned.`);
if (/gmail\.com|yahoo\.com|hotmail\.com|outlook\.com/i.test(info.author_email || ''))
  flags.push('FREE_EMAIL_AUTHOR: Maintainer uses a free email provider. Not inherently bad, but notable for high-profile packages.');
if (deps.length > 30)
  flags.push(`HEAVY_DEPS: ${deps.length} dependencies. Large attack surface.`);
if (!info.summary || info.summary.length < 10)
  flags.push('SPARSE_DESCRIPTION: Very short or missing package description.');

// Green signals
if (ageDays !== null && ageDays > 365 * 2) flags.push(`ESTABLISHED: Package is ${Math.floor(ageDays/365)} years old.`);
if (releaseNames.length > 20) flags.push(`ACTIVE_DEVELOPMENT: ${releaseNames.length} releases show ongoing maintenance.`);
if (vulns.length === 0) flags.push('CLEAN_CVE: No known vulnerabilities in OSV database.');
if (hasSourceRepo) flags.push('HAS_SOURCE: Public source repository available for inspection.');

return [{
  json: {
    package_name: pkgName,
    pypi_found: true,
    signals,
    flags,
    flag_count: flags.length,
    red_flags: flags.filter(f => !['ESTABLISHED','ACTIVE_DEVELOPMENT','CLEAN_CVE','HAS_SOURCE'].some(g => f.startsWith(g))),
    green_flags: flags.filter(f => ['ESTABLISHED','ACTIVE_DEVELOPMENT','CLEAN_CVE','HAS_SOURCE'].some(g => f.startsWith(g)))
  }
}];

const llmRaw = $input.first().json.choices?.[0]?.message?.content || '{}';
const signalData = $('Extract & Analyze Signals').first().json;
const pkgName = signalData.package_name;

if (!signalData.pypi_found) {
  return [{ json: { output: `Package "${pkgName}" not found on PyPI.\n\nThis package does not exist in the PyPI registry. If you expected it to exist, double-check the spelling.\n\nA package that should exist but doesn't is itself a supply-chain signal — someone may have removed it, or you may have a typo that an attacker could register as a typosquat.` } }];
}

let verdict;
try {
  verdict = JSON.parse(llmRaw);
} catch (e) {
  verdict = {
    risk_level: 'UNKNOWN',
    confidence: 0,
    verdict: 'LLM response was not valid JSON. Raw: ' + llmRaw.slice(0, 200),
    key_concerns: [],
    positive_signals: [],
    recommendations: ['Retry the assessment.']
  };
}

const riskEmoji = { LOW: '🟢', MEDIUM: '🟡', HIGH: '🟠', CRITICAL: '🔴', UNKNOWN: '⚪' }[verdict.risk_level] || '⚪';
const s = signalData.signals;

const lines = [];

lines.push(`${riskEmoji} Supply Chain Assessment: ${pkgName}`);
lines.push(`Risk level: ${verdict.risk_level} (confidence: ${verdict.confidence})`);
lines.push(`Verdict: ${verdict.verdict}`);
lines.push('');
lines.push('📦 Package Profile');
lines.push(`Version: ${s.version}`);
lines.push(`Author: ${s.author} (${s.author_email})`);
lines.push(`License: ${s.license}`);
lines.push(`Age: ${s.age_days !== null ? Math.floor(s.age_days / 365) + ' years (' + s.age_days + ' days)' : 'unknown'} — first release: ${s.first_release}`);
lines.push(`Latest release: ${s.latest_release} (${s.days_since_last_release} days ago)`);
lines.push(`Total releases: ${s.total_releases}`);
lines.push(`Dependencies: ${s.dependency_count}`);
lines.push(`Source repo: ${s.has_source_repo ? 'Yes' : 'Not found'}`);
lines.push(`Known CVEs: ${s.known_vulnerabilities}`);
lines.push('');

if (s.typosquat_similar_to && s.typosquat_similar_to.length > 0) {
  lines.push(`⚠️ Typosquat alert: Name is similar to: ${s.typosquat_similar_to.join(', ')}`);
  lines.push('');
}

if (s.vulnerability_details && s.vulnerability_details.length > 0) {
  lines.push('🛡️ Known Vulnerabilities');
  for (const v of s.vulnerability_details.slice(0, 5)) {
    lines.push(`- ${v.id} — ${v.summary || 'No summary'} (severity: ${v.severity})`);
  }
  if (s.vulnerability_details.length > 5) lines.push(`...and ${s.vulnerability_details.length - 5} more`);
  lines.push('');
}

if (signalData.red_flags.length > 0) {
  lines.push('🚩 Red Flags');
  for (const f of signalData.red_flags) lines.push(`- ${f}`);
  lines.push('');
}

if (signalData.green_flags.length > 0) {
  lines.push('✅ Positive Signals');
  for (const f of signalData.green_flags) lines.push(`- ${f}`);
  lines.push('');
}

if (verdict.key_concerns && verdict.key_concerns.length > 0) {
  lines.push('⚠️ Key Concerns');
  for (const c of verdict.key_concerns) lines.push(`- ${c}`);
  lines.push('');
}

if (verdict.recommendations && verdict.recommendations.length > 0) {
  lines.push('💡 Recommendations');
  for (const r of verdict.recommendations) lines.push(`- ${r}`);
}

return [{ json: { output: lines.join('\n') } }];
